// Stores all completed levels
const levelCompletions = []; // Array of { id, userId, levelId, score, time, timestamp, rewardsClaimed, rewards }

// Stores user-specific metadata, e.g., the ID of their last completed level
const users = {}; // Object: { userId: { lastCompletionId: 'some-uuid' } }

// --- Middleware ---
app.use(bodyParser.json()); // Parses incoming request bodies with JSON payloads

// --- Helper Function: Reward Logic ---
/**
 * Determines the rewards based on the player's score and time.
 * This logic can be as complex as needed for your game.
 *
 * @param {number} score - The score achieved in the level.
 * @param {number} time - The time taken to complete the level (in seconds).
 * @returns {string[]} An array of strings representing the awarded items.
 */
function determineRewards(score, time) {
    const rewards = [];

    // Base reward: Coins based on score
    rewards.push(`${Math.floor(score / 10)} Coins`);

    // Tiered rewards based on performance
    if (score >= 1500 && time <= 60) {
        rewards.push('Legendary Chest');
        rewards.push('50 Gems');
    } else if (score >= 1000 && time <= 90) {
        rewards.push('Gold Chest');
        rewards.push('20 Gems');
    } else if (score >= 500 && time <= 180) {
        rewards.push('Silver Chest');
        rewards.push('5 Gems');
    } else {
        rewards.push('Bronze Chest');
    }

    return rewards;
}

// --- API Endpoints ---

/**
 * POST /levels/complete
 *
 * Endpoint for a client to report the completion of a level.
 *
 * Request Body Example:
 * {
 *   "userId": "player123",
 *   "levelId": "level_1-1",
 *   "score": 1250,
 *   "time": 75
 * }
 *
 * Response:
 * - 201 Created: Level completion recorded successfully.
 * - 400 Bad Request: Missing or invalid parameters.
 */
app.post('/levels/complete', (req, res) => {
    const { userId, levelId, score, time } = req.body;

    // Basic input validation
    if (!userId || !levelId || score === undefined || time === undefined) {
        return res.status(400).json({ message: 'Missing required fields: userId, levelId, score, time' });
    }
    if (typeof score !== 'number' || typeof time !== 'number' || score < 0 || time < 0) {
        return res.status(400).json({ message: 'Score and time must be non-negative numbers' });
    }

    const completionId = uuidv4(); // Generate a unique ID for this completion record
    const newCompletion = {
        id: completionId,
        userId,
        levelId,
        score,
        time,
        timestamp: new Date().toISOString(), // Record when the completion was received
        rewardsClaimed: false, // Flag to prevent multiple reward claims for the same completion
        rewards: [] // Will store the actual rewards once claimed
    };

    levelCompletions.push(newCompletion); // Add to our in-memory store

    // Update the user's last completion ID (useful for claiming latest rewards)
    if (!users[userId]) {
        users[userId] = {};
    }
    users[userId].lastCompletionId = completionId;

    console.log(`Level completed: ${JSON.stringify(newCompletion)}`);
    res.status(201).json({
        message: 'Level completion recorded successfully',
        completionId: completionId
    });
});

